96	// ─── Continuation timer ──────────────────────────────────────────────────────
97	
98	const GOAL_CONTINUATION_DELAY_MS = 500;
99	const pendingContinuations = new Map<number, NodeJS.Timeout>();
100	
101	export function cancelPendingContinuation(chatId: number): void {
102	  const h = pendingContinuations.get(chatId);
103	  if (h) {
