109	// ─── Deps interface — mutable state that lives in index.ts ───────────────────
110	
111	export interface RunPromptDeps {
112	  bot: Bot;
113	  sessions: SessionManager;
114	  rateLimitedUntil: () => number;
115	  onRateLimitRecovery: (fn: () => void | Promise<void>) => () => void;
116	  queuePendingMessage: (chatId: number, text: string) => void;
117	  handleRestart: (ctx: Context, opts?: { reason?: string }) => Promise<void>;
