99	export async function handleSpecialistProxy(opts: ProxyHandlerOpts): Promise<boolean> {
100	  const { chatId, text, ctx, session, streamEditIntervalMs, rateLimitedUntil } = opts;
101	  if (!isProxyActive(chatId)) return false;
