249	export async function buildSpecialistHint(text: string): Promise<string> {
250	  if (!config.localLlmPrefilter) return "";
251	  try {
252	    const specialists = getSpecialists();
253	    if (specialists.length === 0) return "";
254	    const descs = specialists.map(s => ({
255	      name: s.name,
256	      description: s.name === "slot-dev" ? "UK slot game development with Cocos 3.6.2"
257	        : s.name === "video-prod" ? "Video production, TTS, ffmpeg, sticker pipeline"
258	        : s.name === "researcher" ? "Deep research on any topic (tech, business, science)"
259	        : s.name,
