265	      return (
266	        `[Specialist routing hint — local pre-filter suggests this message belongs to "${route.target}" specialist. ` +
267	        `Consider using <<SPECIALIST_PROXY:${route.target}|${text.slice(0, 100)}>> if appropriate.]\n\n`
268	      );
269	    }
