}

// ─── Relay tokens (user-facing path) ─────────────────────────────────
if (!relayDone) {
  if (relayTokens.length > 0) console.log(`[chat ${chatId}] relay tokens parsed: ${relayTokens.map(t => t.target).join(", ")}`);
  for (const rt of relayTokens) {
    if (!relayReplyTo) getRelayLoopGuard()?.reopen(rt.target);
    sendRelay(rt.target, rt.text).catch((err) =>
      console.error(`[chat ${chatId}] sendRelay to ${rt.target} failed:`, err));
  }
  for (const rf of relayFileTokens) {
    sendRelayFile(rf.target, rf.path).catch((err) =>
      console.error(`[chat ${chatId}] sendRelayFile to ${rf.target} failed:`, err));
  }
  for (const rd of relayDelegateTokens) {
    if (isLocalSpecialist(rd.target)) {
      console.log(`[chat ${chatId}] dispatching to local specialist "${rd.target}" (id=${rd.payload.id})`);
      saveDelegationContext(chatId, rd.payload.id, session).catch((err) =>
        console.error(`[chat ${chatId}] saveDelegationContext failed:`, err));
      dispatchToSpecialist(rd.target, rd.payload, ctx.from?.id).then(async (result) => {
        console.log(`[chat ${chatId}] specialist "${rd.target}" returned: ${result.payload.status}, summary length=${result.payload.summary?.length ?? 0}`);
        saveArtifact(rd.payload.id, rd.target, rd.payload.goal, result.payload.status as any, result.payload.summary, result.rawOutput).catch((e) => console.warn(`[chat ${chatId}] saveArtifact failed:`, e));
        const delegationCtx = await loadDelegationContext(rd.payload.id);
        const metaPrompt =
          delegationCtx +
          `[系統] Specialist "${rd.target}" 委派結果回傳\n` +
          `Status: ${result.payload.status}\n` +
          `Summary:\n${result.payload.summary}\n` +
          `[End specialist result]\n\n` +
          `請根據委派結果繼續回覆使用者。`;
        const userId = config.allowedUserIds[0] ?? chatId;
        const fakeCtx = {
          chat: { id: chatId, type: "private" as const },
          from: { id: userId, is_bot: false, first_name: rd.target },
          message: { message_id: 0, date: 0, chat: { id: chatId, type: "private" as const }, text: metaPrompt },
          api: bot.api,
          reply: (text: string, extra?: any) => bot.api.sendMessage(chatId, text, extra),
        } as unknown as Context;
        const s = await sessions.get(chatId, userId);
        console.log(`[chat ${chatId}] specialist result injection: session.inflight=${s.inflight}, client.isClosed=${s.client.isClosed}`);
        try {
          await runPrompt(fakeCtx, s, metaPrompt, { kind: "meta" });
          console.log(`[chat ${chatId}] specialist result injection: runPrompt completed`);
        } catch (runErr) {
          console.error(`[chat ${chatId}] specialist result injection: runPrompt threw:`, runErr);
        }
      }).catch((err) => {
        console.error(`[chat ${chatId}] specialist dispatch failed:`, err);
      });
    } else {
      if (!relayReplyTo) getRelayLoopGuard()?.reopen(rd.target);
      registerTask({
        taskId: rd.payload.id,
        type: "relay_delegate",
        peer: rd.target,
        goal: rd.payload.goal.slice(0, 100),
      });
      if (session._lastUploadPath) {
        const attachmentPath = session._lastUploadPath;
        session._lastUploadPath = undefined;
        const caption = `${DELEGATE_PREFIX} ${JSON.stringify(rd.payload)}`;
        if (caption.length <= 1000) {
          sendRelayFile(rd.target, attachmentPath, caption).catch((err) =>
            console.error(`[chat ${chatId}] sendRelayFile (delegate attachment) to ${rd.target} failed:`, err));
        } else {
          sendRelayDelegate(rd.target, rd.payload)
            .then(() => sendRelayFile(rd.target, attachmentPath))
            .catch((err) =>
              console.error(`[chat ${chatId}] relay delegate + attachment fallback to ${rd.target} failed:`, err));
        }
      } else {
        sendRelayDelegate(rd.target, rd.payload).catch((err) =>
          console.error(`[chat ${chatId}] sendRelayDelegate to ${rd.target} failed:`, err));
      }
      if (!relayReplyTo) {
        saveDelegationContext(chatId, rd.payload.id, session).catch((err) =>
          console.error(`[chat ${chatId}] saveDelegationContext failed:`, err));
      }
    }
  }
  for (const rr of relayResultTokens) {
    sendRelayResult(rr.target, rr.payload).catch((err) =>
      console.error(`[chat ${chatId}] sendRelayResult to ${rr.target} failed:`, err));
    getRelayLoopGuard()?.markDone(rr.target);
  }
  if (relayReplyTo && !relayTokens.some((rt) => rt.target === relayReplyTo)) {
    sendRelay(relayReplyTo, body).catch((err) =>
      console.error(`[chat ${chatId}] auto relay reply to ${relayReplyTo} failed:`, err));
  }
}


// ─── Parallel Delegate Dispatch ────────────────────────────────────────
if (parallelDelegateTasks.length > 0) {
  const validTasks = parallelDelegateTasks.filter((t) => isLocalSpecialist(t.target));
  const invalidTasks = parallelDelegateTasks.filter((t) => !isLocalSpecialist(t.target));
  for (const inv of invalidTasks) {
    console.warn(`[chat ${chatId}] PARALLEL_DELEGATE unknown specialist: ${inv.target}`);
  }
  if (validTasks.length > 0) {
    console.log(`[chat ${chatId}] dispatching ${validTasks.length} parallel delegate(s): ${validTasks.map((t) => `${t.target}:${t.taskId}`).join(", ")}`);
    dispatchParallel(validTasks, ctx.from?.id).then(async (results) => {
      console.log(`[chat ${chatId}] parallel dispatch complete: ${results.map((r) => `${r.taskId}=${r.status}`).join(", ")}`);
      for (const r of results) {
        const task = validTasks.find((t) => t.taskId === r.taskId);
        saveArtifact(r.taskId, r.target, task?.payload.goal ?? "", r.status, r.summary, r.rawOutput).catch((e) => console.warn(`[chat ${chatId}] saveArtifact failed:`, e));
      }
      const lines = results.map((r) => {
        const statusIcon = r.status === "done" ? "✅" : r.status === "timeout" ? "⏱️" : "❌";
        return `[PARALLEL_RESULT:${r.taskId}] ${statusIcon} (${r.target}, ${r.status})\n${r.summary}`;
      });
      // Cross-check: when ≥2 specialists completed, ask main agent to
      // compare findings and flag contradictions before replying to user.
      const doneCount = results.filter((r) => r.status === "done").length;
      const crossCheckBlock = doneCount >= 2
        ? `\n\n[Cross-check 指引]\n` +
          `以上有 ${doneCount} 個 specialist 各自獨立完成了任務。回覆使用者前請：\n` +
          `1. 比對各結果之間是否有矛盾、衝突或不一致之處\n` +
          `2. 若有矛盾，明確指出哪些點衝突並給出你的判斷（採信哪個、為什麼）\n` +
          `3. 若無矛盾，整合各結果為統一回覆\n` +
          `[End cross-check]\n`
        : "";
      const metaPrompt =
        `[系統] 並行委派結果回傳（${results.length} 個任務全部完成）\n\n` +
        lines.join("\n\n---\n\n") + "\n\n" +
        `[End parallel results]` + crossCheckBlock + "\n\n" +
        `請根據以上結果繼續回覆使用者。`;
      const userId = config.allowedUserIds[0] ?? chatId;
      const fakeCtx = {
        chat: { id: chatId, type: "private" as const },
        from: { id: userId, is_bot: false, first_name: "parallel" },
        message: { message_id: 0, date: 0, chat: { id: chatId, type: "private" as const }, text: metaPrompt },
        api: bot.api,
        reply: (text: string, extra?: any) => bot.api.sendMessage(chatId, text, extra),
      } as unknown as Context;
      const s = await sessions.get(chatId, userId);
      if (s.inflight) {
        console.log(`[chat ${chatId}] parallel result queued (session inflight)`);
        s._pendingMetaQueue.push({ ctx: fakeCtx, prompt: metaPrompt, opts: { kind: "meta" } });
      } else {
        try {
          await runPrompt(fakeCtx, s, metaPrompt, { kind: "meta" });
        } catch (err) {
          console.error(`[chat ${chatId}] parallel result injection failed:`, err);
        }
      }
    }).catch((err) => {
      console.error(`[chat ${chatId}] parallel dispatch failed:`, err);
    });
  }
}

