  for (const rf of relayFileTokens) {
    sendRelayFile(rf.target, rf.path).catch((err) =>
      console.error(`[chat ${chatId}] sendRelayFile to ${rf.target} failed:`, err));
  }
  for (const rd of relayDelegateTokens) {
    if (isLocalSpecialist(rd.target)) {
      console.log(`[chat ${chatId}] dispatching to local specialist "${rd.target}" (id=${rd.payload.id})`);
      saveDelegationContext(chatId, rd.payload.id, session).catch((err) =>
        console.error(`[chat ${chatId}] saveDelegationContext failed:`, err));
      dispatchToSpecialist(rd.target, rd.payload, ctx.from?.id).then(async (result) => {
        console.log(`[chat ${chatId}] specialist "${rd.target}" returned: ${result.payload.status}, summary length=${result.payload.summary?.length ?? 0}`);
        saveArtifact(rd.payload.id, rd.target, rd.payload.goal, result.payload.status as any, result.payload.summary, result.rawOutput).catch((e) => console.warn(`[chat ${chatId}] saveArtifact failed:`, e));
        const delegationCtx = await loadDelegationContext(rd.payload.id);
        const metaPrompt =
          delegationCtx +
          `[系統] Specialist "${rd.target}" 委派結果回傳\n` +
          `Status: ${result.payload.status}\n` +
          `Summary:\n${result.payload.summary}\n` +
          `[End specialist result]\n\n` +
          `請根據委派結果繼續回覆使用者。`;
        const userId = config.allowedUserIds[0] ?? chatId;
        const { runPrompt, sessions } = deps();
